mapper.select:
SELECT bi.*, p.project_name, c.`name` as customerName FROM elder_bill bi LEFT JOIN elder_project p ON p.id = bi.project_id LEFT JOIN elder_customer c on c.id = bi.customer_id WHERE bi.del_flag = 0
AND bi.project_id IN (
#{id}
)
AND bi.project_id = #{data.projectId}
AND bi.`customer_id` = #{data.customerId}
AND c.`name` LIKE concat(concat('%',#{data.customerName}),'%')
AND bi.checkin_id LIKE concat(concat('%',#{data.checkinId}),'%')
AND bi.bill_no LIKE concat(concat('%',#{data.billNo}),'%')
AND bi.status = #{data.status}
AND bi.bill_month LIKE concat(concat('%',#{data.billMonth}),'%')
ORDER BY bi.create_time DESC
